import React, { useState, useEffect } from 'react';

const ProductList = () => {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(false);
  const [filters, setFilters] = useState({
    category: '',
    search: '',
    sort: ''
  });

  useEffect(() => {
    fetchProducts();
  }, [filters]);

  const fetchProducts = async () => {
    setLoading(true);
    try {
      // Fetch all products from DummyJSON (100+ products)
      const response = await fetch('https://dummyjson.com/products?limit=100');
      const data = await response.json();
      
      // Filter for electronics-related categories only
      const electronicsKeywords = ['phone', 'laptop', 'computer', 'tablet', 'headphone', 'monitor', 'keyboard', 'mouse', 'camera', 'mobile'];
      
      let processedProducts = (data.products || []).filter(p => 
        electronicsKeywords.some(keyword => 
          p.title.toLowerCase().includes(keyword) || 
          p.category.toLowerCase().includes(keyword)
        )
      );
      
      // Filter by search
      if (filters.search) {
        processedProducts = processedProducts.filter(p => 
          p.title.toLowerCase().includes(filters.search.toLowerCase()) ||
          p.description.toLowerCase().includes(filters.search.toLowerCase())
        );
      }
      
      // Sort products
      if (filters.sort === 'price-asc') {
        processedProducts.sort((a, b) => a.price - b.price);
      } else if (filters.sort === 'price-desc') {
        processedProducts.sort((a, b) => b.price - a.price);
      } else if (filters.sort === 'rating') {
        processedProducts.sort((a, b) => (b.rating || 0) - (a.rating || 0));
      }
      
      setProducts(processedProducts);
    } catch (error) {
      console.error('Failed to fetch products:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleFilterChange = (e) => {
    const { name, value } = e.target;
    setFilters(prev => ({
      ...prev,
      [name]: value
    }));
  };

  return (
    <div className="product-list">
      <div className="filters">
        <input
          type="text"
          name="search"
          placeholder="Search products..."
          value={filters.search}
          onChange={handleFilterChange}
        />
        <select name="sort" value={filters.sort} onChange={handleFilterChange}>
          <option value="">Sort By</option>
          <option value="price-asc">Price: Low to High</option>
          <option value="price-desc">Price: High to Low</option>
          <option value="rating">Best Rating</option>
        </select>
      </div>

      {loading ? (
        <div>Loading products...</div>
      ) : (
        <div className="products-grid">
          {products.map(product => (
            <div key={product.id} className="product-card">
              <img 
                src={product.image} 
                alt={product.title}
                onError={handleImageError}
              />
              <h3>{product.title}</h3>
              <p className="price">₹{Math.round(product.price * 83)}</p>
              <p className="description">{product.description.substring(0, 50)}...</p>
              <div className="rating">⭐ {product.rating?.rate || 'N/A'}</div>
              <button className="view-btn">View Details</button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default ProductList;
